import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const response = await fetch('/platform/automation/v1/executions/' + execution_id + '/tasks/get-job-status/result');
  const body = await response.json();

  const status = body?.status || {};
  const succeeded = Number(status.succeeded || 0);
  const failed = Number(status.failed || 0);
  const active = Number(status.active || 0);

  console.log('Kubernetes Job status', { succeeded, failed, active });

  if (failed > 0) {
    throw new Error('Kubernetes remediation job failed. failed=' + failed);
  }

  if (succeeded > 0) {
    return body;
  }

  throw new Error('Kubernetes remediation job still running; retrying...');
}
